const event = $input.first().json.body || $input.first().json;
const type = event.type;
const user = event.user_name || 'Investor';
const amount = event.amount || '0';
const property = event.property || '';

const templates = {
  'purchase_confirmed': `Hi ${user}! Your investment of $${amount} in ${property} is confirmed. Your shares are now in your portfolio. 🎉`,
  'rent_available': `Hi ${user}, you have $${amount} rental income available to claim from ${property}. Log in to hub.nfstay.com to claim.`,
  'rent_claimed': `Hi ${user}, your claim of $${amount} has been submitted. Bank transfers process every Tuesday.`,
  'commission_earned': `Hi ${user}, you earned $${amount} commission! It will be claimable in 14 days. 💰`,
  'commission_claimable': `Hi ${user}, your $${amount} commission is ready to claim! Log in to hub.nfstay.com`,
  'payout_completed': `Hi ${user}, your payout of £${amount} has been sent to your bank account ✅`,
  'payout_failed': `⚠️ ADMIN: Payout of £${amount} failed for ${user}. Check Revolut dashboard.`,
  'proposal_created': `New proposal for ${property}: Vote now on hub.nfstay.com 🗳️`,
  'bank_details_saved': `Hi ${user}, your bank details have been saved for NFsTay payouts. If you didn't do this, contact us immediately.`,
  'batch_ready': `NFsTay Payout Batch Ready ✅\nPayees: ${event.count || 0}\nTotal: £${event.gbp_total || 0}\n\n👉 Open Revolut app to approve.`
};

const message = templates[type] || `NFsTay: ${type}`;
const isAdmin = ['payout_failed', 'batch_ready'].includes(type);

return [{ json: { message, type, isAdmin, email: event.email, phone: event.phone, user_id: event.user_id, contactId: event.ghl_contact_id } }];
